        if matches!(sym.storage, Storage::Static) {
            ty |= SM_STATIC;
        }
        if sym.arity == -1 && !matches!(sym.storage, Storage::Auto) {
            ty |= SM_DATA;
        } else if sym.arity >= 0 || matches!(sym.symbol_type, SymbolType::Function) {
            ty |= SM_FUNCTIONS;
