for order_idx in 0..self.option_order.len() {
    let slot = self.option_order[order_idx];
    let namelen = self.options[slot].name.len();
    let mut neg = NegMatch::NotTried;

    if namelen == 1 && !self.single_dash {
        continue;
    }

    let name_match = {
        let opt = &self.options[slot];
        optlen <= namelen && opt.name.get(..optlen) == Some(&optname[..optlen])
    };
    if !name_match {
        neg = self.negmatch_state(slot, optname, optlen);
    }

    if name_match || !matches!(neg, NegMatch::NoMatch) {
        match found {
            0 => {
                found_idx = Some(slot);
                found = 1;
                negated = matches!(neg, NegMatch::Exact | NegMatch::Inexact);
                if optlen == namelen || matches!(neg, NegMatch::Exact) {
                    break;
                }
            }
            1 => {
                found = 2;
                self.error(format!(
                    "option '{}{}' is ambiguous; possibilities:",
                    ["", "-", "--"][self.dash_count.min(2)],
                    &optname[..optlen]
                ));
                if let Some(prev_idx) = found_idx {
                    let prev_name = self.options[prev_idx].name.clone();
                    self.error(format!(
                        "{}{}{}",
                        ["", "-", "--"][self.dash_count.min(2)],
                        if negated { self.negation.as_str() } else { "" },
                        prev_name
                    ));
                    if !negated
                        && !matches!(
                            self.negmatch_state(prev_idx, optname, optlen),
                            NegMatch::NoMatch
                        )
                    {
                        self.error(format!(
                            "{}{}{}",
                            ["", "-", "--"][self.dash_count.min(2)],
                            self.negation,
                            prev_name
                        ));
                    }
                }
                let opt_name = self.options[slot].name.clone();
                self.error(format!(
                    "{}{}{}",
                    ["", "-", "--"][self.dash_count.min(2)],
                    if matches!(neg, NegMatch::Exact | NegMatch::Inexact) {
                        self.negation.as_str()
                    } else {
                        ""
                    },
                    opt_name
                ));
            }
            _ => {
                let opt_name = self.options[slot].name.clone();
                self.error(format!(
                    "{}{}{}",
                    ["", "-", "--"][self.dash_count.min(2)],
                    if matches!(neg, NegMatch::Exact | NegMatch::Inexact) {
                        self.negation.as_str()
                    } else {
                        ""
                    },
                    opt_name
                ));
            }
        }
    }
}

pub fn prepare_optdef(&mut self, opt_index: usize, scan_flags: &mut i32) {
    let short_code = self.find_short_name(opt_index);
    let Some(opt) = self.options.get_mut(opt_index) else {
        return;
    };

    if opt.code == 0 {
        opt.code = short_code;
    }

    if opt.name == "help" {
        opt.action = ParseAction::Help;
    } else if opt.name == "usage" {
        opt.action = ParseAction::Usage;
    } else if opt.name == "version" {
        opt.action = ParseAction::Version;
    }

    if opt.short_name().is_some() {
        *scan_flags |= 0x01;
    } else {
        *scan_flags |= 0x02;
    }
}

pub fn getident(&mut self, idptr: Option<&mut Ident>, parm_ptr: &mut Option<&mut i32>) -> i32 {
    let pos = self.mark();
    let mut bc = 0;

    loop {
        bc += 1;
        if self.nexttoken() == 0 {
            if self.verbose {
                self.file_error("unexpected end of file", None);
            }
            return -1;
        }
        if self.tok.token_type != '(' as i32 {
            break;
        }
    }

    if self.tok.token_type == 256 {
        let name = self.tok.token.clone();
        let line = self.tok.line;

        while bc > 0 {
            if self.nexttoken() == 0 {
                if self.verbose {
                    self.file_error("unexpected end of file", None);
                }
                return -1;
            }
            if self.tok.token_type == ')' as i32 {
                bc -= 1;
            } else {
                break;
            }
        }

        if bc == 0 {
            if let Some(ident) = idptr {
                ident.name = name;
                ident.line = line;
                *parm_ptr = Some(&mut ident.parmcnt);
            }
            return 0;
        }
    }

    self.putback_to_mark(pos);
    1
}

pub fn dirdcl(&mut self, idptr: &mut Ident) -> i32 {
    let mut local_parmcnt = None::<i32>;
    let mut parm_ptr = None;

    if self.tok.token_type == '(' as i32 {
        match self.getident(Some(idptr), &mut parm_ptr) {
            0 => {}
            -1 => return 1,
            _ => {
                self.dcl(idptr);
                if self.tok.token_type != ')' as i32 && self.verbose {
                    self.file_error("expected `)'", Some(&self.tok));
                    return 1;
                }
            }
        }
    } else if self.tok.token_type == 256 {
        idptr.name = self.tok.token.clone();
        idptr.line = self.tok.line;
        local_parmcnt = Some(idptr.parmcnt);
        parm_ptr = local_parmcnt.as_mut();
    }

    loop {
        match self.nexttoken() {
            x if x == '[' as i32 => {
                if self.find_closing_paren('[' as i32, 1) == -1 {
                    self.file_error("unexpected end of file in declaration", None);
                    return -1;
                }
            }
            x if x == '(' as i32 => {
                self.maybe_parm_list(parm_ptr.as_deref_mut());
                if let Some(value) = local_parmcnt {
                    idptr.parmcnt = value;
                }
                if self.tok.token_type != ')' as i32 && self.verbose {
                    self.file_error("expected `)'", Some(&self.tok));
                    return 1;
                }
            }
            _ => {
                self.putback();
                break;
            }
        }
    }
    0
}

